// TestNamespaceScopedEvaluation tests flag evaluation with different namespaces.
func TestNamespaceScopedEvaluation(t *testing.T) {
	// Create mock store with flags in different namespaces
	store := &MockEvaluationStore{
		flags: map[string]*flipt.Flag{
			"production:feature": {
				NamespaceKey: "production",
				Key:          "feature",
				Name:         "Production Feature",
				Enabled:      true,
				Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			},
			"staging:feature": {
				NamespaceKey: "staging",
				Key:          "feature",
				Name:         "Staging Feature",
				Enabled:      false,
				Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			},
		},
		rules: map[string][]*storage.EvaluationRule{},
	}

	// Create evaluation server
	logger := zaptest.NewLogger(t)
	evalServer := evaluation.New(logger, store)

	// Create a simple HTTP handler that wraps the gRPC service
	handler := createEvaluationHTTPHandler(evalServer)

	// Create test HTTP server
	server := httptest.NewServer(handler)
	defer server.Close()

	// Test production namespace evaluation
	prodReq := rpcevaluation.EvaluationRequest{
		FlagKey:      "feature",
		NamespaceKey: "production",
		EntityId:     "user-prod",
		RequestId:    "req-prod",
	}

	prodData, err := protojson.Marshal(&prodReq)
	require.NoError(t, err)

	prodResp, err := http.Post(server.URL+"/evaluate/v1/boolean", "application/json", bytes.NewReader(prodData))
	require.NoError(t, err)
	defer prodResp.Body.Close()

	assert.Equal(t, http.StatusOK, prodResp.StatusCode)

	// Test staging namespace evaluation
	stagingReq := rpcevaluation.EvaluationRequest{
		FlagKey:      "feature",
		NamespaceKey: "staging",
		EntityId:     "user-staging",
		RequestId:    "req-staging",
	}

	stagingData, err := protojson.Marshal(&stagingReq)
	require.NoError(t, err)

	stagingResp, err := http.Post(server.URL+"/evaluate/v1/boolean", "application/json", bytes.NewReader(stagingData))
	require.NoError(t, err)
	defer stagingResp.Body.Close()

	assert.Equal(t, http.StatusOK, stagingResp.StatusCode)
}

// TestInvalidRequestBody tests handling of invalid JSON request bodies.
