// TestBatchEvaluation tests batch evaluation endpoint.
func TestBatchEvaluation(t *testing.T) {
	// Create mock store with multiple flags
	store := &MockEvaluationStore{
		flags: map[string]*flipt.Flag{
			"default:flag1": {
				NamespaceKey: "default",
				Key:          "flag1",
				Name:         "Flag 1",
				Enabled:      true,
				Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			},
			"default:flag2": {
				NamespaceKey: "default",
				Key:          "flag2",
				Name:         "Flag 2",
				Enabled:      true,
				Type:         flipt.FlagType_VARIANT_FLAG_TYPE,
			},
		},
		rules: map[string][]*storage.EvaluationRule{},
	}

	// Create evaluation server
	logger := zaptest.NewLogger(t)
	evalServer := evaluation.New(logger, store)

	// Create a simple HTTP handler that wraps the gRPC service
	handler := createEvaluationHTTPHandler(evalServer)

	// Create test HTTP server
	server := httptest.NewServer(handler)
	defer server.Close()

	// Create batch evaluation request
	batchReq := rpcevaluation.BatchEvaluationRequest{
		RequestId: "batch-123",
		Requests: []*rpcevaluation.EvaluationRequest{
			{
				FlagKey:      "flag1",
				NamespaceKey: "default",
				EntityId:     "user-batch-1",
				RequestId:    "req-batch-1",
			},
			{
				FlagKey:      "flag2",
				NamespaceKey: "default",
				EntityId:     "user-batch-2",
				RequestId:    "req-batch-2",
			},
		},
	}

	batchData, err := protojson.Marshal(&batchReq)
	require.NoError(t, err)

	resp, err := http.Post(server.URL+"/evaluate/v1/batch", "application/json", bytes.NewReader(batchData))
	require.NoError(t, err)
	defer resp.Body.Close()

	// Verify batch response
	assert.Equal(t, http.StatusOK, resp.StatusCode)

	var result rpcevaluation.BatchEvaluationResponse
	err = protojson.Unmarshal(readBody(t, resp), &result)
	require.NoError(t, err)

	assert.Equal(t, "batch-123", result.RequestId)
	assert.Equal(t, 2, len(result.Responses))
}

// TestResponseFormatAndContentType tests that responses are properly formatted JSON.
func TestResponseFormatAndContentType(t *testing.T) {
	// Create mock store with a flag
	store := &MockEvaluationStore{
		flags: map[string]*flipt.Flag{
			"default:test_flag": {
				NamespaceKey: "default",
				Key:          "test_flag",
				Name:         "Test Flag",
				Enabled:      true,
				Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			},
		},
		rules: map[string][]*storage.EvaluationRule{},
	}

	// Create evaluation server
	logger := zaptest.NewLogger(t)
	evalServer := evaluation.New(logger, store)

	// Create a simple HTTP handler that wraps the gRPC service
	handler := createEvaluationHTTPHandler(evalServer)

	// Create test HTTP server
	server := httptest.NewServer(handler)
	defer server.Close()

	// Send evaluation request
	reqBody := rpcevaluation.EvaluationRequest{
		FlagKey:      "test_flag",
		NamespaceKey: "default",
		EntityId:     "user-response-test",
		RequestId:    "req-response-test",
	}

	reqData, err := protojson.Marshal(&reqBody)
	require.NoError(t, err)

	resp, err := http.Post(server.URL+"/evaluate/v1/boolean", "application/json", bytes.NewReader(reqData))
	require.NoError(t, err)
	defer resp.Body.Close()

	// Verify response
	assert.Equal(t, http.StatusOK, resp.StatusCode)

	// Verify response body is valid JSON
	var result interface{}
	body := readBody(t, resp)
	err = json.Unmarshal(body, &result)
	require.NoError(t, err, "Response should be valid JSON")

	// Verify response contains expected fields
	var boolResp rpcevaluation.BooleanEvaluationResponse
	err = protojson.Unmarshal(body, &boolResp)
	require.NoError(t, err)

	assert.NotEmpty(t, boolResp.FlagKey)
	assert.NotEmpty(t, boolResp.RequestId)
}

// Helper functions

// createEvaluationHTTPHandler creates a simple HTTP handler for evaluation endpoints.
// This is a minimal implementation that directly calls the gRPC service methods.
func createEvaluationHTTPHandler(evalServer *evaluation.Server) http.Handler {
	mux := http.NewServeMux()

	mux.HandleFunc("/evaluate/v1/boolean", func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
			return
		}

		var req rpcevaluation.EvaluationRequest
		if err := protojson.New().UnmarshalOptions.Unmarshal(readBody(nil, r), &req); err != nil {
			// Return error response in gRPC status format
			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusBadRequest)
			errorResp := map[string]interface{}{
				"code":    3, // INVALID_ARGUMENT
				"message": "Invalid request body",
			}
			json.NewEncoder(w).Encode(errorResp)
			return
		}

		resp, err := evalServer.Boolean(r.Context(), &req)
		if err != nil {
			// Return error response in gRPC status format
			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusInternalServerError)
			errorResp := map[string]interface{}{
				"code":    2, // INTERNAL
				"message": err.Error(),
			}
			json.NewEncoder(w).Encode(errorResp)
			return
		}

		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		respData, _ := protojson.Marshal(resp)
		w.Write(respData)
	})

	mux.HandleFunc("/evaluate/v1/variant", func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
			return
		}

		var req rpcevaluation.EvaluationRequest
		if err := protojson.New().UnmarshalOptions.Unmarshal(readBody(nil, r), &req); err != nil {
			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusBadRequest)
			errorResp := map[string]interface{}{
				"code":    3, // INVALID_ARGUMENT
				"message": "Invalid request body",
			}
			json.NewEncoder(w).Encode(errorResp)
			return
		}

		resp, err := evalServer.Variant(r.Context(), &req)
		if err != nil {
			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusInternalServerError)
			errorResp := map[string]interface{}{
				"code":    2, // INTERNAL
				"message": err.Error(),
			}
			json.NewEncoder(w).Encode(errorResp)
			return
		}

		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		respData, _ := protojson.Marshal(resp)
		w.Write(respData)
	})

	mux.HandleFunc("/evaluate/v1/batch", func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
			return
		}

		var req rpcevaluation.BatchEvaluationRequest
		if err := protojson.New().UnmarshalOptions.Unmarshal(readBody(nil, r), &req); err != nil {
			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusBadRequest)
			errorResp := map[string]interface{}{
				"code":    3, // INVALID_ARGUMENT
				"message": "Invalid request body",
			}
			json.NewEncoder(w).Encode(errorResp)
			return
		}

		resp, err := evalServer.Batch(r.Context(), &req)
		if err != nil {
			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusInternalServerError)
			errorResp := map[string]interface{}{
				"code":    2, // INTERNAL
				"message": err.Error(),
			}
			json.NewEncoder(w).Encode(errorResp)
			return
		}

		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		respData, _ := protojson.Marshal(resp)
		w.Write(respData)
	})

	return mux
}

// readBody reads the HTTP request body and returns it as bytes.
// If t is nil, it ignores errors; otherwise it fails the test on error.
func readBody(t *testing.T, r interface {
	Body interface {
		Read(p []byte) (n int, err error)
	}
}) []byte {
	var buf bytes.Buffer
	_, err := buf.ReadFrom(r.Body)
	if err != nil && t != nil {
		t.Fatalf("Failed to read body: %v", err)
	}
	return buf.Bytes()
}

