		Context: map[string]string{
			"plan": "premium",
		},
	}

	reqData, err := protojson.Marshal(&reqBody)
	require.NoError(t, err)

	resp, err := http.Post(server.URL+"/evaluate/v1/variant", "application/json", bytes.NewReader(reqData))
