// createEvaluationHTTPHandler creates a simple HTTP handler for evaluation endpoints.
// This is a minimal implementation that directly calls the gRPC service methods.
func createEvaluationHTTPHandler(evalServer *evaluation.Server) http.Handler {
	mux := http.NewServeMux()

	mux.HandleFunc("/evaluate/v1/boolean", func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
			return
		}

		var req rpcevaluation.EvaluationRequest
		if err := protojson.Unmarshal(readBodyFromRequest(nil, r), &req); err != nil {
			// Return error response in gRPC status format
			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusBadRequest)
			errorResp := map[string]interface{}{
				"code":    3, // INVALID_ARGUMENT
				"message": "Invalid request body",
			}
			json.NewEncoder(w).Encode(errorResp)
			return
		}

		resp, err := evalServer.Boolean(r.Context(), &req)
		if err != nil {
			// Return error response in gRPC status format
			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusInternalServerError)
			errorResp := map[string]interface{}{
				"code":    2, // INTERNAL
				"message": err.Error(),
			}
			json.NewEncoder(w).Encode(errorResp)
			return
		}

		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		respData, _ := protojson.Marshal(resp)
		w.Write(respData)
	})

	mux.HandleFunc("/evaluate/v1/variant", func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
