			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusBadRequest)
			errorResp := map[string]interface{}{
				"code":    3, // INVALID_ARGUMENT
				"message": "Invalid request body",
			}
			json.NewEncoder(w).Encode(errorResp)
			return
		}

		resp, err := evalServer.Variant(r.Context(), &req)
		if err != nil {
			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusInternalServerError)
			errorResp := map[string]interface{}{
				"code":    2, // INTERNAL
				"message": err.Error(),
			}
			json.NewEncoder(w).Encode(errorResp)
			return
		}

		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		respData, _ := protojson.Marshal(resp)
		w.Write(respData)
	})

	mux.HandleFunc("/evaluate/v1/batch", func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
			return
		}

		var req rpcevaluation.BatchEvaluationRequest
		if err := protojson.Unmarshal(readBodyFromRequest(nil, r), &req); err != nil {
			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusBadRequest)
			errorResp := map[string]interface{}{
				"code":    3, // INVALID_ARGUMENT
				"message": "Invalid request body",
			}
			json.NewEncoder(w).Encode(errorResp)
			return
		}

		resp, err := evalServer.Batch(r.Context(), &req)
		if err != nil {
			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusInternalServerError)
			errorResp := map[string]interface{}{
				"code":    2, // INTERNAL
				"message": err.Error(),
			}
			json.NewEncoder(w).Encode(errorResp)
			return
		}

		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		respData, _ := protojson.Marshal(resp)
		w.Write(respData)
	})

	return mux
}

// readBodyFromResponse reads the HTTP response body and returns it as bytes.
func readBodyFromResponse(t *testing.T, resp *http.Response) []byte {
	var buf bytes.Buffer
	_, err := buf.ReadFrom(resp.Body)
	if err != nil && t != nil {
		t.Fatalf("Failed to read response body: %v", err)
	}
	return buf.Bytes()
}

// readBodyFromRequest reads the HTTP request body and returns it as bytes.
func readBodyFromRequest(t *testing.T, req *http.Request) []byte {
	var buf bytes.Buffer
	_, err := buf.ReadFrom(req.Body)
	if err != nil && t != nil {
		t.Fatalf("Failed to read request body: %v", err)
	}
